239:   */
240:  crawl(): Promise<CrawlResult | null>;
242:  /**
243:   * Show a rig by id. Throws if not found.
244:   */
245:  show(id: string): Promise<RigDoc>;
247:  /**
248:   * List rigs with optional filters, ordered by createdAt descending.
249:   */
250:  list(filters?: RigFilters): Promise<RigDoc[]>;
252:  /**
253:   * Find the rig for a given writ. Returns null if no rig exists.
254:   */
255:  forWrit(writId: string): Promise<RigDoc | null>;
257:  /**
258:   * Manually clear a block on a specific engine, regardless of checker result.
259:   * Throws if the engine is not blocked.
260:   */
261:  resume(rigId: string, engineId: string): Promise<void>;
263:  /**
264:   * Look up a registered block type by ID.
265:   */
266:  getBlockType(id: string): BlockType | undefined;
268:  /**
269:   * List all registered block types with summary info.
270:   */
271:  listBlockTypes(): BlockTypeInfo[];
272:}
274:// ── Configuration ─────────────────────────────────────────────────────
276:/**
277: * Spider apparatus configuration — lives under the `spider` key in guild.json.
278: */
279:export interface SpiderConfig {
280:  /**
281:   * Polling interval for crawlContinual tool (milliseconds).
282:   * Default: 5000.
283:   */
284:  pollIntervalMs?: number;
285:  /**
286:   * Build command to pass to quick engines.
287:   */
288:  buildCommand?: string;
289:  /**
290:   * Test command to pass to quick engines.
291:   */
292:  testCommand?: string;
293:  /**
294:   * Named rig templates. Keys are template names (not writ types).
295:   * Templates are looked up by name via rigTemplateMappings.
296:   * A template named 'default' is used as the fallback when no mapping matches.
297:   */
298:  rigTemplates?: Record<string, RigTemplate>;
299:  /**
300:   * Writ type → rig template name mappings.
301:   * 'default' key is the fallback for unmatched writ types.
302:   * Config mappings override kit-contributed mappings for the same writ type.
303:   */
304:  rigTemplateMappings?: Record<string, string>;
305:  /**
306:   * User-defined variables available in rig template givens via '$vars.<key>'.
307:   * Values are passed through literally (string, number, boolean).
308:   * Variables resolving to undefined (key absent) cause the givens key to be omitted.
309:   */
310:  variables?: Record<string, unknown>;
311:}
313:// ── Engine yield shapes ───────────────────────────────────────────────
315:/**
316: * Yields from the `draft` clockwork engine.
317: * The Spider stores these in the engine instance and passes them
318: * to downstream engines via context.upstream['draft'].
319: */
320:export interface DraftYields {
321:  /** The draft's unique id. */
322:  draftId: string;
323:  /** Codex this draft belongs to. */
324:  codexName: string;
325:  /** Git branch name for the draft. */
326:  branch: string;
327:  /** Absolute filesystem path to the draft's worktree. */
328:  path: string;
329:  /** HEAD commit SHA at the time the draft was opened. Used by review engine to compute diffs. */
330:  baseSha: string;
331:}
333:/**
334: * Yields from the `seal` clockwork engine.
335: */
336:export interface SealYields {
337:  /** The commit SHA at head of the target branch after sealing. */
338:  sealedCommit: string;
339:  /** Git strategy used. */
340:  strategy: 'fast-forward' | 'rebase';
341:  /** Number of retry attempts. */
342:  retries: number;
343:  /** Number of inscriptions (commits) sealed. */
344:  inscriptionsSealed: number;
345:}
347:/**
348: * Yields from the `implement` quick engine.
349: * Set by the Spider's collect step when the Animator session completes.
350: */
351:export interface ImplementYields {
352:  /** The Animator session id. */
353:  sessionId: string;
354:  /** Terminal status of the session. */
355:  sessionStatus: 'completed' | 'failed';
356:}
358:/**
359: * A single mechanical check (build or test) run by the review engine
360: * before launching the reviewer session.
361: */
362:export interface MechanicalCheck {
363:  /** Check name. */
364:  name: 'build' | 'test';
365:  /** Whether the command exited with code 0. */
366:  passed: boolean;
367:  /** Combined stdout+stderr, truncated to 4KB. */
368:  output: string;
369:  /** Wall-clock duration of the check in milliseconds. */
370:  durationMs: number;
371:}
373:/**
374: * Yields from the `review` quick engine.
375: * Assembled by the Spider's collect step from session.output and session.metadata.
376: */
377:export interface ReviewYields {
378:  /** The Animator session id. */
379:  sessionId: string;
380:  /** Reviewer's overall assessment — true if the review passed. */
381:  passed: boolean;
382:  /** Structured markdown findings from the reviewer's final message. */
383:  findings: string;
384:  /** Mechanical check results run before the reviewer session. */
385:  mechanicalChecks: MechanicalCheck[];
386:}
388:/**
389: * Yields from the `revise` quick engine.
390: * Set by the Spider's collect step when the Animator session completes.
391: */
392:export interface ReviseYields {
393:  /** The Animator session id. */
394:  sessionId: string;
395:  /** Terminal status of the session. */
396:  sessionStatus: 'completed' | 'failed';
397:}
399:// ── Input request types ──────────────────────────────────────────────
401:export type InputRequestStatus = 'pending' | 'completed' | 'rejected';
403:export interface ChoiceQuestionSpec {
404:  type: 'choice';
405:  /** Human-readable question text. */
406:  label: string;
407:  /** Key → display label options map. */
408:  options: Record<string, string>;
409:  /** When true, the patron can supply a freeform answer instead of selecting. */
410:  allowCustom: boolean;
411:}
413:export interface BooleanQuestionSpec {
414:  type: 'boolean';
415:  /** Human-readable question text. */
416:  label: string;
417:}
419:export interface TextQuestionSpec {
420:  type: 'text';
421:  /** Human-readable question text. */
422:  label: string;
423:}
425:export type QuestionSpec = ChoiceQuestionSpec | BooleanQuestionSpec | TextQuestionSpec;
427:/** Discriminated choice answer — selected from options or freeform custom. */
428:export type ChoiceAnswer = { selected: string } | { custom: string };
430:/**
431: * Answer value union. Runtime type is determined by the corresponding QuestionSpec:
432: * - choice → ChoiceAnswer (object with 'selected' or 'custom' key)
433: * - boolean → boolean
434: * - text → string
435: */
436:export type AnswerValue = ChoiceAnswer | boolean | string;
438:/**
439: * An input request document stored in the spider/input-requests book.
440: * Created by engines before blocking; answered by patrons via CLI tools.
441: */
442:export interface InputRequestDoc {
443:  [key: string]: unknown;
444:  /** Unique ID via generateId('ir', 4). */
445:  id: string;
446:  /** Rig this request belongs to. */
447:  rigId: string;

