1:/**
2: * Spider — custom Oculus API routes.
3: *
4: * Contributes GET /api/spider/config, which returns an aggregated snapshot
5: * of the Spider's registered configuration: rig templates, engine designs,
6: * and block types.
7: *
8: * Does NOT import from @shardworks/oculus-apparatus to avoid a circular
9: * package dependency. The route shape is compatible with RouteContribution
10: * from the Oculus types.
11: */
13:import type { Context } from 'hono';
14:import { guild } from '@shardworks/nexus-core';
15:import type { FabricatorApi } from '@shardworks/fabricator-apparatus';
16:import type { SpiderApi, SpiderConfig } from './types.ts';
18:export const spiderRoutes = [
19:  {
20:    method: 'GET',
21:    path: '/api/spider/config',
22:    handler: (c: Context) => {
23:      const g = guild();
24:      const spiderConfig: SpiderConfig = g.guildConfig().spider ?? {};
25:      const fabricator = g.apparatus<FabricatorApi>('fabricator');
26:      const spider = g.apparatus<SpiderApi>('spider');
28:      return c.json({
29:        rigTemplates: spiderConfig.rigTemplates ?? {},
30:        engineDesigns: fabricator.listEngineDesigns(),
31:        blockTypes: spider.listBlockTypes(),
32:      });
33:    },
34:  },
35:];

