1:/**
2: * Spider dashboard — vanilla JS IIFE.
3: * No framework, no modules, no imports.
4: */
5:(function () {
6:  'use strict';
8:  // ── State ──────────────────────────────────────────────────────────────
10:  var rigs = [];
11:  var currentRig = null;
12:  var selectedEngineId = null;
13:  var sortField = 'createdAt';
14:  var sortDir = 'desc';
15:  var configData = null;
16:  var currentStatusFilter = '';
18:  // ── Badge mapping ──────────────────────────────────────────────────────
20:  function badgeClass(status) {
21:    switch (status) {
22:      case 'completed': return 'badge--success';
23:      case 'running':   return 'badge--active';
24:      case 'failed':    return 'badge--error';
25:      case 'blocked':   return 'badge--warning';
26:      case 'pending':
27:      case 'cancelled':
28:      default:          return '';
29:    }
30:  }
32:  function badgeHtml(status) {
33:    var cls = badgeClass(status);
34:    var fullCls = cls ? 'badge ' + cls : 'badge';
35:    return '<span class="' + fullCls + '">' + esc(status) + '</span>';
36:  }
38:  // ── Utility ────────────────────────────────────────────────────────────
40:  function esc(s) {
41:    if (s == null) return '';
42:    return String(s)
43:      .replace(/&/g, '&amp;')
44:      .replace(/</g, '&lt;')
45:      .replace(/>/g, '&gt;')
46:      .replace(/"/g, '&quot;');
47:  }
49:  function formatDate(iso) {
50:    if (!iso) return '';
51:    try {
52:      return new Date(iso).toLocaleString();
53:    } catch (e) {
54:      return iso;
55:    }
56:  }
58:  function engineSummary(engines) {
59:    if (!engines || engines.length === 0) return '0/0';
60:    var completed = engines.filter(function (e) { return e.status === 'completed'; }).length;
61:    return completed + '/' + engines.length + ' completed';
62:  }
64:  // ── Fetch rigs ─────────────────────────────────────────────────────────
66:  function fetchRigs(statusFilter) {
67:    currentStatusFilter = statusFilter || '';
68:    var url = '/api/rig/list?limit=100';
69:    if (statusFilter) {
70:      url += '&status=' + encodeURIComponent(statusFilter);
71:    }
72:    fetch(url)
73:      .then(function (r) { return r.json(); })
74:      .then(function (data) {
75:        rigs = Array.isArray(data) ? data : [];
76:        renderRigList();
77:      })
78:      .catch(function (err) {
79:        console.error('Failed to fetch rigs:', err);
80:        rigs = [];
81:        renderRigList();
82:      });
83:  }
85:  // ── Render rig list ────────────────────────────────────────────────────
87:  function renderRigList() {
88:    var writFilter = (document.getElementById('writ-filter') || {}).value || '';
89:    var dateFrom = (document.getElementById('date-from') || {}).value || '';
90:    var dateTo = (document.getElementById('date-to') || {}).value || '';
92:    var filtered = rigs.filter(function (rig) {
93:      // WritId filter (case-insensitive)
94:      if (writFilter && !(rig.writId || '').toLowerCase().includes(writFilter.toLowerCase())) {
95:        return false;
96:      }
97:      // Date range filter
98:      if (dateFrom && rig.createdAt < dateFrom) {
99:        return false;
100:      }
101:      if (dateTo && rig.createdAt > dateTo + 'T23:59:59') {
102:        return false;
103:      }
104:      return true;
105:    });
107:    // Sort
108:    filtered.sort(function (a, b) {
109:      var av = a[sortField] || '';
110:      var bv = b[sortField] || '';
111:      var cmp = av < bv ? -1 : av > bv ? 1 : 0;
112:      return sortDir === 'asc' ? cmp : -cmp;
113:    });
115:    var tbody = document.getElementById('rig-tbody');
116:    var empty = document.getElementById('rig-empty');
117:    var table = document.getElementById('rig-table');
119:    if (!tbody) return;
121:    if (filtered.length === 0) {
122:      tbody.innerHTML = '';
123:      if (empty) empty.style.display = '';
124:      if (table) table.style.display = 'none';
125:      return;
126:    }
128:    if (empty) empty.style.display = 'none';
129:    if (table) table.style.display = '';
131:    var rows = filtered.map(function (rig) {
132:      return '<tr>' +
133:        '<td><a class="rig-link" href="#" data-rig-id="' + esc(rig.id) + '">' + esc(rig.id) + '</a></td>' +
134:        '<td><a href="/pages/clerk/?writ=' + esc(rig.writId) + '">' + esc(rig.writId) + '</a></td>' +
135:        '<td>' + badgeHtml(rig.status) + '</td>' +
136:        '<td>' + esc(engineSummary(rig.engines)) + '</td>' +
137:        '<td>' + esc(formatDate(rig.createdAt)) + '</td>' +
138:        '</tr>';
139:    });
141:    tbody.innerHTML = rows.join('');
143:    // Wire rig-link clicks
144:    var links = tbody.querySelectorAll('.rig-link');
145:    for (var i = 0; i < links.length; i++) {
146:      (function (link) {
147:        link.addEventListener('click', function (e) {
148:          e.preventDefault();
149:          var rigId = link.getAttribute('data-rig-id');
150:          var rig = rigs.find(function (r) { return r.id === rigId; });
151:          if (rig) showRigDetail(rig);
152:        });
153:      })(links[i]);
154:    }
155:  }
157:  // ── Show rig detail ────────────────────────────────────────────────────
159:  function showRigDetail(rig) {
160:    currentRig = rig;
161:    selectedEngineId = null;
163:    document.getElementById('rig-list-view').style.display = 'none';
164:    document.getElementById('rig-detail-view').style.display = '';
166:    document.getElementById('detail-title').textContent = 'Rig: ' + rig.id;
168:    var metaTable = document.getElementById('detail-meta');
169:    metaTable.innerHTML =
170:      '<tbody>' +
171:      '<tr><th>ID</th><td>' + esc(rig.id) + '</td></tr>' +
172:      '<tr><th>Writ</th><td><a href="/pages/clerk/?writ=' + esc(rig.writId) + '">' + esc(rig.writId) + '</a></td></tr>' +
173:      '<tr><th>Status</th><td>' + badgeHtml(rig.status) + '</td></tr>' +
174:      '<tr><th>Created</th><td>' + esc(formatDate(rig.createdAt)) + '</td></tr>' +
175:      '</tbody>';
177:    renderPipeline(rig);
179:    var engineDetail = document.getElementById('engine-detail');
180:    if (engineDetail) engineDetail.style.display = 'none';
181:  }
183:  // ── Render pipeline ────────────────────────────────────────────────────
185:  function topoSort(engines) {
186:    var order = [];
187:    var visited = {};
188:    function visit(e) {
189:      if (visited[e.id]) return;
190:      visited[e.id] = true;
191:      (e.upstream || []).forEach(function (uid) {
192:        var up = engines.find(function (x) { return x.id === uid; });
193:        if (up) visit(up);
194:      });
195:      order.push(e);
196:    }
197:    engines.forEach(visit);
198:    return order;
199:  }
201:  function renderPipeline(rig) {
202:    var pipeline = document.getElementById('pipeline');
203:    if (!pipeline) return;
204:    pipeline.innerHTML = '';
206:    var engines = rig.engines || [];
207:    if (engines.length === 0) {
208:      pipeline.textContent = 'No engines.';
209:      return;
210:    }
212:    var sorted = topoSort(engines);
214:    sorted.forEach(function (engine, idx) {
215:      // Add arrow before node (except first)
216:      if (idx > 0) {
217:        var arrow = document.createElement('div');
218:        arrow.className = 'pipeline-arrow';
219:        arrow.textContent = '\u2192';
220:        pipeline.appendChild(arrow);
221:      }
223:      var node = document.createElement('div');
224:      node.className = 'pipeline-node' + (engine.id === selectedEngineId ? ' selected' : '');
225:      node.setAttribute('data-engine-id', engine.id);
227:      var idSpan = document.createElement('span');
228:      idSpan.className = 'node-id';
229:      idSpan.textContent = engine.id;
230:      node.appendChild(idSpan);
232:      var badgeEl = document.createElement('span');
233:      var bc = badgeClass(engine.status);
234:      badgeEl.className = bc ? 'badge ' + bc : 'badge';
235:      badgeEl.textContent = engine.status;
236:      node.appendChild(badgeEl);
238:      // Show upstream list if this engine has upstreams beyond the previous node
239:      if (engine.upstream && engine.upstream.length > 1) {
240:        var upEl = document.createElement('span');
241:        upEl.style.fontSize = '10px';
242:        upEl.style.color = 'var(--text-dim, #888)';
243:        upEl.textContent = '\u2191 ' + engine.upstream.join(', ');
244:        node.appendChild(upEl);
245:      }
247:      node.addEventListener('click', function () {
248:        showEngineDetail(engine);
249:      });
251:      pipeline.appendChild(node);
252:    });
253:  }
255:  // ── Show engine detail ─────────────────────────────────────────────────
257:  function showEngineDetail(engine) {
258:    selectedEngineId = engine.id;
260:    // Update pipeline node selection
261:    var nodes = document.querySelectorAll('.pipeline-node');
262:    for (var i = 0; i < nodes.length; i++) {
263:      var n = nodes[i];
264:      if (n.getAttribute('data-engine-id') === engine.id) {
265:        n.classList.add('selected');
266:      } else {
267:        n.classList.remove('selected');
268:      }
269:    }
271:    var panel = document.getElementById('engine-detail');
272:    var title = document.getElementById('engine-detail-title');
273:    var body = document.getElementById('engine-detail-body');
275:    if (!panel || !title || !body) return;
277:    title.textContent = 'Engine: ' + engine.id;
278:    panel.style.display = '';
280:    var html = '<dl class="engine-detail-field">';
282:    html += '<dt>Status</dt><dd>' + badgeHtml(engine.status) + '</dd>';
283:    html += '<dt>Design ID</dt><dd>' + esc(engine.designId) + '</dd>';
284:    html += '<dt>Upstream</dt><dd>' + esc((engine.upstream || []).join(', ') || '(none)') + '</dd>';
285:    html += '<dt>Started At</dt><dd>' + esc(formatDate(engine.startedAt) || '—') + '</dd>';
286:    html += '<dt>Completed At</dt><dd>' + esc(formatDate(engine.completedAt) || '—') + '</dd>';
288:    if (engine.error) {
289:      html += '<dt>Error</dt><dd style="color:var(--red,#f55)">' + esc(engine.error) + '</dd>';
290:    }
291:    if (engine.sessionId) {
292:      html += '<dt>Session ID</dt><dd>' + esc(engine.sessionId) + '</dd>';
293:    }
295:    if (engine.block) {
296:      html += '<dt>Block Type</dt><dd>' + esc(engine.block.type) + '</dd>';
297:      html += '<dt>Blocked At</dt><dd>' + esc(formatDate(engine.block.blockedAt)) + '</dd>';
298:      if (engine.block.message) {
299:        html += '<dt>Block Message</dt><dd>' + esc(engine.block.message) + '</dd>';
300:      }
301:      if (engine.block.lastCheckedAt) {
302:        html += '<dt>Last Checked</dt><dd>' + esc(formatDate(engine.block.lastCheckedAt)) + '</dd>';
303:      }
304:      html += '<dt>Block Condition</dt><dd><pre style="margin:0;font-size:11px">' + esc(JSON.stringify(engine.block.condition, null, 2)) + '</pre></dd>';
305:    }
307:    html += '</dl>';
309:    // Collapsible givensSpec
310:    html += '<details class="collapsible"><summary>Givens Spec</summary>' +
311:      '<pre><code>' + esc(JSON.stringify(engine.givensSpec, null, 2)) + '</code></pre></details>';
313:    // Collapsible yields
314:    if (engine.yields !== undefined) {
315:      html += '<details class="collapsible"><summary>Yields</summary>' +
316:        '<pre><code>' + esc(JSON.stringify(engine.yields, null, 2)) + '</code></pre></details>';
317:    }
319:    body.innerHTML = html;
320:  }
322:  // ── Back to list ───────────────────────────────────────────────────────
324:  function backToList() {
325:    currentRig = null;
326:    selectedEngineId = null;
327:    document.getElementById('rig-detail-view').style.display = 'none';
328:    document.getElementById('rig-list-view').style.display = '';
329:  }
331:  // ── Config tab ─────────────────────────────────────────────────────────
333:  function fetchConfig() {
334:    fetch('/api/spider/config')
335:      .then(function (r) { return r.json(); })
336:      .then(function (data) {
337:        configData = data;
338:        renderConfig();
339:      })
340:      .catch(function (err) {
341:        console.error('Failed to fetch config:', err);
342:      });
343:  }
345:  function renderConfig() {
346:    if (!configData) return;
348:    // Rig templates
349:    var templatesSection = document.getElementById('templates-section');
350:    if (templatesSection) {
351:      var rigTemplates = configData.rigTemplates || {};
352:      var keys = Object.keys(rigTemplates);
353:      if (keys.length === 0) {
354:        templatesSection.innerHTML = '<p class="empty-state">No rig templates configured.</p>';
355:      } else {
356:        templatesSection.innerHTML = keys.map(function (key) {
357:          return '<div class="template-block">' +
358:            '<h3>' + esc(key) + '</h3>' +
359:            '<pre><code>' + esc(JSON.stringify(rigTemplates[key], null, 2)) + '</code></pre>' +
360:            '</div>';
361:        }).join('');
362:      }
363:    }
365:    // Engine designs table
366:    var designsTbody = document.getElementById('designs-tbody');
367:    if (designsTbody) {
368:      var designs = configData.engineDesigns || [];
369:      if (designs.length === 0) {
370:        designsTbody.innerHTML = '<tr><td colspan="3" class="empty-state">No engine designs registered.</td></tr>';
371:      } else {
372:        designsTbody.innerHTML = designs.map(function (d) {
373:          return '<tr>' +
374:            '<td>' + esc(d.id) + '</td>' +
375:            '<td>' + esc(d.pluginId) + '</td>' +
376:            '<td>' + (d.hasCollect ? 'Yes' : 'No') + '</td>' +
377:            '</tr>';
378:        }).join('');
379:      }
380:    }
382:    // Block types table
383:    var blocktypesTbody = document.getElementById('blocktypes-tbody');
384:    if (blocktypesTbody) {
385:      var blockTypes = configData.blockTypes || [];
386:      if (blockTypes.length === 0) {
387:        blocktypesTbody.innerHTML = '<tr><td colspan="3" class="empty-state">No block types registered.</td></tr>';
388:      } else {
389:        blocktypesTbody.innerHTML = blockTypes.map(function (bt) {
390:          return '<tr>' +
391:            '<td>' + esc(bt.id) + '</td>' +
