164:/**
165: * Resolve a template engine's givens map using a variables context.
166: * '$writ' → WritDoc, '$vars.<key>' → spiderConfig.variables[key].
167: * Keys resolving to undefined are omitted from the output.
168: * Non-'$' prefixed values are passed through as literals.
169: */
170:function resolveGivens(
171:  givens: Record<string, unknown> | undefined,
172:  context: { writ: WritDoc; spiderConfig: SpiderConfig },
173:): Record<string, unknown> {
174:  const result: Record<string, unknown> = {};
175:  for (const [key, value] of Object.entries(givens ?? {})) {
176:    if (typeof value !== 'string' || !value.startsWith('$')) {
177:      result[key] = value;
178:    } else {
179:      const normalized = normalizeVarRef(value);
180:      if (normalized === '$writ') {
181:        result[key] = context.writ;
182:      } else if (/^\$vars\.[a-zA-Z_][a-zA-Z0-9_]*$/.test(normalized)) {
183:        const varKey = normalized.slice('$vars.'.length);
184:        const resolved = (context.spiderConfig.variables ?? {})[varKey];
185:        if (resolved !== undefined) {
186:          result[key] = resolved;
187:        }
188:        // undefined → omit key entirely
189:      }
190:      // Unrecognized $-prefixed strings are caught at validation time
191:    }
192:  }
193:  return result;
194:}
