255:        function registerCustomRoute(route: RouteContribution, pluginId: string): void {
256:          if (!route.path.startsWith('/api/')) {
257:            console.warn(`[oculus] Custom route "${route.path}" from "${pluginId}" must start with /api/ — skipped`);
258:            return;
259:          }
260:          const method = route.method.toLowerCase() as keyof typeof app;
261:          (app[method] as (path: string, handler: (c: unknown) => unknown) => void)(
262:            route.path,
263:            route.handler as (c: unknown) => unknown,
264:          );
265:          customRoutePaths.add(route.path);
266:        }
268:        // ── Page serving helper ───────────────────────────────────────
269:        function resolveDirForPackage(packageName: string, dir: string): string {
270:          return path.join(g.home, 'node_modules', packageName, dir);
271:        }
273:        function registerPage(page: PageContribution, resolvedDir: string): void {
274:          pages.push({ ...page });
276:          app.get(`/pages/${page.id}/*`, async (c) => {
277:            const requestPath = c.req.path;
278:            const prefix = `/pages/${page.id}/`;
279:            const filePath = requestPath.slice(prefix.length) || 'index.html';
281:            // Prevent directory traversal
282:            if (filePath.includes('..')) {
283:              return c.text('Not found', 404);
284:            }
286:            const absolutePath = path.join(resolvedDir, filePath);
288:            // Ensure file is within resolved dir
289:            if (!absolutePath.startsWith(resolvedDir)) {
290:              return c.text('Not found', 404);
291:            }
293:            try {
294:              const content = fs.readFileSync(absolutePath);
295:              const mimeType = getMimeType(absolutePath);
297:              // Only inject chrome for the root index.html
298:              const isIndexHtml = filePath === 'index.html' || filePath === '';
299:              if (isIndexHtml && mimeType.startsWith('text/html')) {
300:                const html = content.toString('utf-8');
301:                const navHtml = buildNavHtml(pages);
302:                const injected = injectChrome(html, '/static/style.css', navHtml);
303:                return new Response(injected, {
304:                  headers: { 'Content-Type': 'text/html; charset=utf-8' },
305:                });
306:              }
308:              return new Response(content, {
309:                headers: { 'Content-Type': mimeType },
310:              });
311:            } catch {
312:              return c.text('Not found', 404);
313:            }
314:          });
315:        }
317:        // ── Tool route registration helper ───────────────────────────
318:        function registerToolRoute(
319:          toolDef: import('@shardworks/tools-apparatus').ToolDefinition,
320:          instrumentarium: InstrumentariumApi,
321:        ): void {
322:          const routePath = toolNameToRoute(toolDef.name);
323:          const method = permissionToMethod(toolDef.permission);
325:          if (mappedToolRoutes.has(routePath)) return;
327:          if (customRoutePaths.has(routePath)) {
328:            console.warn(
329:              `[oculus] Tool route ${method} ${routePath} conflicts with custom route from plugin — skipped`,
330:            );
331:            return;
332:          }
334:          void instrumentarium; // suppress unused warning
336:          const shape = toolDef.params.shape as Record<string, z.ZodTypeAny>;
338:          if (method === 'GET') {
339:            app.get(routePath, async (c) => {
340:              try {
341:                const rawQuery = c.req.query();
342:                const coerced = coerceParams(shape, rawQuery);
343:                const validated = toolDef.params.parse(coerced);
344:                const result = await toolDef.handler(validated);
345:                return c.json(result);
346:              } catch (err) {
347:                if (err instanceof z.ZodError) {
348:                  return c.json({ error: err.message, details: err.issues }, 400);
349:                }
350:                const message = err instanceof Error ? err.message : String(err);
351:                return c.json({ error: message }, 500);
352:              }
353:            });
354:          } else if (method === 'DELETE') {
355:            app.delete(routePath, async (c) => {
356:              try {
357:                const body = await c.req.json();
358:                const validated = toolDef.params.parse(body);
359:                const result = await toolDef.handler(validated);
360:                return c.json(result);
361:              } catch (err) {
362:                if (err instanceof z.ZodError) {
