361:              } catch (err) {
362:                if (err instanceof z.ZodError) {
363:                  return c.json({ error: err.message, details: err.issues }, 400);
364:                }
365:                const message = err instanceof Error ? err.message : String(err);
366:                return c.json({ error: message }, 500);
367:              }
368:            });
369:          } else {
370:            app.post(routePath, async (c) => {
371:              try {
372:                const body = await c.req.json();
373:                const validated = toolDef.params.parse(body);
374:                const result = await toolDef.handler(validated);
375:                return c.json(result);
376:              } catch (err) {
377:                if (err instanceof z.ZodError) {
378:                  return c.json({ error: err.message, details: err.issues }, 400);
379:                }
380:                const message = err instanceof Error ? err.message : String(err);
381:                return c.json({ error: message }, 500);
382:              }
383:            });
384:          }
386:          mappedToolRoutes.add(routePath);
387:        }
389:        // ── Scan contributions from a kit ────────────────────────────
390:        function scanKit(kit: LoadedKit): void {
391:          const oculusKit = kit.kit as OculusKit;
393:          if (oculusKit.routes) {
394:            for (const route of oculusKit.routes) {
395:              registerCustomRoute(route, kit.id);
396:            }
397:          }
399:          if (oculusKit.pages) {
400:            for (const page of oculusKit.pages) {
401:              const resolvedDir = resolveDirForPackage(kit.packageName, page.dir);
402:              registerPage(page, resolvedDir);
403:            }
404:          }
405:        }
407:        function scanApparatus(apparatus: LoadedApparatus): void {
408:          if (!apparatus.apparatus.supportKit) return;
409:          const oculusKit = apparatus.apparatus.supportKit as OculusKit;
411:          if (oculusKit.routes) {
412:            for (const route of oculusKit.routes) {
413:              registerCustomRoute(route, apparatus.id);
414:            }
415:          }
417:          if (oculusKit.pages) {
418:            for (const page of oculusKit.pages) {
419:              const resolvedDir = resolveDirForPackage(apparatus.packageName, page.dir);
420:              registerPage(page, resolvedDir);
421:            }
422:          }
423:        }
425:        // ── Scan existing kits and apparatuses ───────────────────────
426:        for (const kit of g.kits()) {
427:          scanKit(kit);
428:        }
429:        for (const apparatus of g.apparatuses()) {
430:          scanApparatus(apparatus);
431:        }
433:        // ── Register custom routes first ─────────────────────────────
434:        // (already done in scanKit/scanApparatus above)
436:        // ── Register tool routes ─────────────────────────────────────
437:        const instrumentarium = g.apparatus<InstrumentariumApi>('tools');
438:        const allTools = instrumentarium.list();
439:        const patronTools = allTools.filter(
440:          (r) => !r.definition.callableBy || r.definition.callableBy.includes('patron'),
441:        );
443:        for (const resolved of patronTools) {
444:          registerToolRoute(resolved.definition, instrumentarium);
445:        }
447:        // ── GET /api/_status ─────────────────────────────────────────
448:        app.get('/api/_status', (c) => {
449:          const config = g.guildConfig();
450:          return c.json({
451:            guild: config.name,
452:            nexus: VERSION,
453:            home: g.home,
454:            model: config.settings?.model ?? '(not set)',
455:            port: serverPort,
456:            apparatuses: g.apparatuses().map((a) => ({ id: a.id, version: a.version })),
457:            kits: g.kits().map((k) => ({ id: k.id, version: k.version })),
458:            failedPlugins: g.failedPlugins().map((f) => ({ id: f.id, reason: f.reason })),
459:            warnings: g.startupWarnings(),
460:            config: config,
461:          });
462:        });
464:        // ── GET /api/_tools ──────────────────────────────────────────
465:        app.get('/api/_tools', (c) => {
466:          const tools = instrumentarium.list().filter(
467:            (r) => !r.definition.callableBy || r.definition.callableBy.includes('patron'),
468:          );
470:          const entries = tools.map((r) => ({
471:            name: r.definition.name,
472:            route: toolNameToRoute(r.definition.name),
473:            method: permissionToMethod(r.definition.permission),
474:            description: r.definition.description,
475:            params: extractParams(r.definition.params),
476:          }));
478:          return c.json(entries);
479:        });
481:        // ── Static assets ────────────────────────────────────────────
482:        const staticDir = path.join(import.meta.dirname, 'static');
483:        app.get('/static/*', (c) => {
484:          const requestPath = c.req.path;
485:          const filePath = requestPath.slice('/static/'.length);
487:          if (filePath.includes('..')) {
488:            return c.text('Not found', 404);
489:          }
491:          const absolutePath = path.join(staticDir, filePath);
492:          try {
493:            const content = fs.readFileSync(absolutePath);
494:            const mimeType = getMimeType(absolutePath);
495:            return new Response(content, {
496:              headers: { 'Content-Type': mimeType },
497:            });
498:          } catch {
499:            return c.text('Not found', 404);
500:          }
501:        });
503:        // ── Home page ────────────────────────────────────────────────
504:        app.get('/', (c) => {
505:          const config = g.guildConfig();
506:          const guildName = config.name;
507:          const navHtml = buildNavHtml(pages);
508:          const model = config.settings?.model ?? '(not set)';
510:          // ── Identity card ──────────────────────────────────────────
511:          const identityCard = `<div class="card" style="margin-bottom: 16px;">
512:    <h2>Identity</h2>
513:    <table class="data-table">
514:      <tbody>
515:        <tr><td>Guild</td><td>${escapeHtml(guildName)}</td></tr>
516:        <tr><td>Nexus</td><td>${escapeHtml(VERSION)}</td></tr>
517:        <tr><td>Home</td><td>${escapeHtml(g.home)}</td></tr>
518:        <tr><td>Model</td><td>${escapeHtml(model)}</td></tr>
519:        <tr><td>Port</td><td>${serverPort}</td></tr>
520:      </tbody>
521:    </table>
522:  </div>`;
524:          // ── Warnings card (conditional) ────────────────────────────
525:          const warnings = g.startupWarnings();
526:          const warningsCard = warnings.length > 0
527:            ? `<div class="card" style="margin-bottom: 16px;">
528:    <h2>Warnings</h2>
529:    <ul>
530:      ${warnings.map((w) => `<li><span class="badge badge--warning">${escapeHtml(w)}</span></li>`).join('\n      ')}
531:    </ul>
532:  </div>`
533:            : '';
535:          // ── Plugins table ──────────────────────────────────────────
536:          const apparatuses = g.apparatuses();
537:          const kits = g.kits();
538:          const failedPlugins = g.failedPlugins();
540:          let pluginRows = '';
541:          if (apparatuses.length === 0 && kits.length === 0 && failedPlugins.length === 0) {
542:            pluginRows = `<tr><td colspan="4" class="empty-state">No plugins loaded.</td></tr>`;
543:          } else {
544:            pluginRows += apparatuses.map((a) =>
545:              `<tr>
546:          <td>${escapeHtml(a.id)}</td>
547:          <td>apparatus</td>
548:          <td>${escapeHtml(a.version)}</td>
549:          <td><span class="badge badge--success">apparatus</span></td>
550:        </tr>`,
551:            ).join('\n');
552:            pluginRows += kits.map((k) =>
553:              `<tr>
554:          <td>${escapeHtml(k.id)}</td>
555:          <td>kit</td>
556:          <td>${escapeHtml(k.version)}</td>
557:          <td><span class="badge badge--info">kit</span></td>
558:        </tr>`,
559:            ).join('\n');
560:            pluginRows += failedPlugins.map((f) =>
561:              `<tr>
562:          <td>${escapeHtml(f.id)}</td>
563:          <td>—</td>
564:          <td>—</td>
565:          <td><span class="badge badge--error" title="${escapeHtml(f.reason)}">failed</span> <span style="color: var(--text-dim); font-size: 11px;">${escapeHtml(f.reason)}</span></td>
566:        </tr>`,
567:            ).join('\n');
568:          }
570:          const pluginsCard = `<div class="card" style="margin-bottom: 16px;">
571:    <h2>Plugins</h2>
572:    <table class="data-table">
573:      <thead>
574:        <tr><th>Id</th><th>Type</th><th>Version</th><th>Status</th></tr>
575:      </thead>
576:      <tbody>
577:        ${pluginRows}
578:      </tbody>
579:    </table>

