14:  --yellow: #e0af68;
15:  --cyan: #7dcfff;
16:  --magenta: #bb9af7;
17:  --blue: #7aa2f7;
18:  --font-mono: "SF Mono", "Fira Code", "JetBrains Mono", monospace;
19:}
21:/* ── Element-type selectors ──────────────────────────────────────── */
22:body {
23:  background: var(--bg);
24:  color: var(--text);
25:  font-family: var(--font-mono);
26:  font-size: 13px;
27:  line-height: 1.6;
28:  margin: 0;
29:  padding: 0;
30:}
32:h1, h2, h3, h4 {
33:  color: var(--text-bright);
34:  font-weight: 600;
35:}
37:a {
38:  color: var(--cyan);
39:  text-decoration: none;
40:}
42:a:hover {
43:  text-decoration: underline;
44:}
46:table {
47:  width: 100%;
48:  border-collapse: collapse;
49:}
51:th, td {
52:  text-align: left;
53:  padding: 8px;
54:  border-bottom: 1px solid var(--border);
55:}
57:th {
58:  color: var(--text-dim);
59:  font-weight: 500;
60:}
62:button {
63:  background: var(--blue);
