1:/**
2: * session-show tool — show full detail for a single session by id.
3: *
4: * Reads the complete session record from The Animator's `sessions` book
5: * in The Stacks, including tokenUsage, metadata, and all indexed fields.
6: *
7: * See: docs/specification.md (animator § session-show tool)
8: */
10:import { tool } from '@shardworks/tools-apparatus';
11:import { guild } from '@shardworks/nexus-core';
12:import { z } from 'zod';
13:import type { StacksApi } from '@shardworks/stacks-apparatus';
14:import type { SessionDoc } from '../types.ts';
16:export default tool({
17:  name: 'session-show',
18:  description: 'Show full detail for a single session by id',
19:  instructions:
20:    'Returns the complete session record from The Stacks, including ' +
21:    'tokenUsage, metadata, and all indexed fields.',
22:  params: {
23:    id: z.string().describe('Session id'),
24:  },
25:  permission: 'read',
26:  handler: async (params) => {
27:    const stacks = guild().apparatus<StacksApi>('stacks');
28:    const sessions = stacks.readBook<SessionDoc>('animator', 'sessions');
30:    const session = await sessions.get(params.id);
31:    if (!session) {
32:      throw new Error(`Session "${params.id}" not found.`);
33:    }
34:    return session;
35:  },
36:});

