784:   * Phase 1 — collect.
785:   *
786:   * Find the first running engine with a sessionId whose session has
787:   * reached a terminal state. Populate yields and advance the engine
788:   * (and possibly the rig) to completed or failed.
789:   *
790:   * After collecting a completed engine, check whether the rig has
791:   * become blocked (no running engines, no runnable engines, some blocked).
792:   */
793:  async function tryCollect(): Promise<CrawlResult | null> {
794:    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
795:    for (const rig of runningRigs) {
796:      for (const engine of rig.engines) {
797:        if (engine.status !== 'running' || !engine.sessionId) continue;
799:        const session = await sessionsBook.get(engine.sessionId);
800:        if (!session || session.status === 'running') continue;
802:        // Terminal session found — collect.
803:        const now = new Date().toISOString();
805:        if (session.status === 'failed' || session.status === 'timeout') {
806:          await failEngine(rig, engine.id, session.error ?? `Session ${session.status}`);
807:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
808:        }
810:        // Completed session — assemble yields via engine's collect() or generic default.
811:        const design = fabricator.getEngineDesign(engine.designId);
812:        let yields: unknown;
813:        if (design?.collect) {
814:          const givens = { ...engine.givensSpec };
815:          const upstream = buildUpstreamMap(rig);
816:          const context = { rigId: rig.id, engineId: engine.id, upstream };
817:          yields = await design.collect(engine.sessionId!, givens, context);
818:        } else {
819:          yields = {
820:            sessionId: session.id,
821:            sessionStatus: session.status,
822:            ...(session.output !== undefined ? { output: session.output } : {}),
823:          };
824:        }
826:        if (!isJsonSerializable(yields)) {
827:          await failEngine(rig, engine.id, 'Session yields are not JSON-serializable');
828:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
829:        }
831:        const updatedEngines = rig.engines.map((e) =>
832:          e.id === engine.id
833:            ? { ...e, status: 'completed' as const, yields, completedAt: now }
834:            : e,
835:        );
837:        const allCompleted = updatedEngines.every((e) => e.status === 'completed');
839:        if (allCompleted) {
840:          await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'completed' });
841:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'completed' };
842:        }
844:        // Check whether completing this engine has caused the rig to become blocked
845:        if (isRigBlocked(updatedEngines)) {
846:          await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'blocked' });
847:          return { action: 'rig-blocked', rigId: rig.id, writId: rig.writId };
848:        }
850:        await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'running' });
851:        return { action: 'engine-completed', rigId: rig.id, engineId: engine.id };
852:      }
853:    }
854:    return null;
855:  }
857:  /**
858:   * Phase 2 — checkBlocked.
859:   *
860:   * Query rigs with status 'running' or 'blocked'. For each blocked engine,
861:   * run the registered checker (respecting pollIntervalMs). If cleared,
862:   * transition the engine back to pending and restore the rig to running.
863:   * If not cleared, update lastCheckedAt and continue to the next engine.
864:   */
865:  async function tryCheckBlocked(): Promise<CrawlResult | null> {
866:    // Fetch both running rigs (may have blocked engines) and blocked rigs
867:    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
868:    const blockedRigs = await rigsBook.find({ where: [['status', '=', 'blocked']] });
869:    const rigs = [...runningRigs, ...blockedRigs];
871:    for (const rig of rigs) {
872:      for (const engine of rig.engines) {
873:        if (engine.status !== 'blocked' || !engine.block) continue;
875:        const blockType = blockTypeRegistry.get(engine.block.type);
876:        if (!blockType) continue; // Type was unregistered after block was created; skip
878:        // Poll interval throttle
879:        if (blockType.pollIntervalMs !== undefined && engine.block.lastCheckedAt) {
880:          const elapsed = Date.now() - new Date(engine.block.lastCheckedAt).getTime();
881:          if (elapsed < blockType.pollIntervalMs) continue;
882:        }
884:        let result: CheckResult;
885:        try {
886:          result = await blockType.check(engine.block.condition);
887:        } catch (err) {
888:          // Log warning, skip — engine stays blocked, retry next cycle
889:          console.warn(
890:            `Block checker "${engine.block.type}" threw for engine "${engine.id}" in rig "${rig.id}":`,
891:            err,
892:          );
893:          continue;
894:        }
896:        if (result.status === 'failed') {
897:          // Permanent failure — fail the engine and rig immediately
898:          const message = result.reason
899:            ? `Block "${engine.block.type}" failed: ${result.reason}`
900:            : `Block "${engine.block.type}" failed permanently`;
901:          await failEngine(rig, engine.id, message);
902:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
903:        }
905:        if (result.status !== 'cleared') {
906:          // Pending (or any unexpected status) — update lastCheckedAt and continue checking other engines
907:          const now = new Date().toISOString();
908:          const updatedEngines = rig.engines.map((e) =>
909:            e.id === engine.id
910:              ? { ...e, block: { ...e.block!, lastCheckedAt: now } }
911:              : e,
912:          );
913:          await rigsBook.patch(rig.id, { engines: updatedEngines });
914:          continue; // Check next engine
915:        }
