import { streamSSE } from 'hono/streaming';
return streamSSE(c, async (stream) => {
  await stream.writeSSE({ event: 'chunk', data: JSON.stringify(payload) });
});
```

`packages/plugins/parlour/src/static/parlour/app.js` — manual SSE parsing from `ReadableStream` (works for GET too):
```javascript
const reader = response.body.getReader();
// buffer lines, split on \n\n, parse event/data fields
```

